const admin = require\('firebase-admin'\);
admin.initializeApp\({ projectId: 'installer-portal-6000' }\);
const db = admin.firestore\(\);

const now = new Date\(\);
const monthStart = new Date\(now.getFullYear\(\), now.getMonth\(\), 1\);
const monthEnd = new Date\(now.getFullYear\(\), now.getMonth\(\) + 1, 0, 23, 59, 59\);

db.collection\('jobs'\).where\('startDt', '>=', monthStart\).where\('startDt', '<=', monthEnd\).get\(\).then\(snap => {
    console.log\('Jobs this month:', snap.size\);
    let total = 0;
    let withBalance = 0;
    snap.docs.slice\(0, 5\).forEach\(d => {
        const data = d.data\(\);
        const bal = data.financials?.balanceDue;
        console.log\(' -', data.customerName || d.id, '| balanceDue:', bal, '| startDt:', data.startDt?.toDate?.\(\)\);
    }\);
    snap.docs.forEach\(d => {
        const bal = parseFloat\(d.data\(\).financials?.balanceDue\) || 0;
        if \(bal > 0\) withBalance++;
        total += bal;
    }\);
    console.log\('Total with balanceDue > 0:', withBalance, '/', snap.size\);
    console.log\('Sum of balanceDue:', total\);
    process.exit\(0\);
}\);
")

Bash(node -e "
const admin = require\('firebase-admin'\);
admin.initializeApp\({ projectId: 'installer-portal-6000' }\);
const db = admin.firestore\(\);
const del = admin.firestore.FieldValue.delete\(\);

db.collection\('jobs'\).get\(\).then\(async snap => {
    let cleared = 0;
    for \(let i = 0; i < snap.docs.length; i += 500\) {
        const batch = db.batch\(\);
        snap.docs.slice\(i, i + 500\).forEach\(doc => {
            if \(doc.data\(\).financials\) {
                batch.update\(doc.ref, { financials: del }\);
                cleared++;
            }
        }\);
        await batch.commit\(\);
    }
    console.log\('Cleared financials from', cleared, 'jobs'\);
    process.exit\(0\);
}\);
")

