Bash(node -e "
const admin = require\('firebase-admin'\);
admin.initializeApp\({ projectId: 'installer-portal-6000' }\);
const db = admin.firestore\(\);

const windowStart = new Date\(\); windowStart.setDate\(windowStart.getDate\(\) - 30\);
const windowEnd   = new Date\(\); windowEnd.setDate\(windowEnd.getDate\(\) + 90\);

db.collection\('jobs'\).get\(\).then\(async snap => {
    const stale = snap.docs.filter\(d => {
        const startDt = d.data\(\).startDt?.toDate?.\(\);
        if \(!startDt\) return false;
        return startDt < windowStart || startDt > windowEnd;
    }\);
    console.log\('Orphan jobs to delete:', stale.length\);
    if \(stale.length === 0\) { process.exit\(0\); return; }
    const batch = db.batch\(\);
    stale.forEach\(d => batch.delete\(d.ref\)\);
    await batch.commit\(\);
    console.log\('Deleted.'\);
    process.exit\(0\);
}\);
")
